+		@Override
+		public TypeInformation getResultType() {
+			return Types.SQL_DATE;
+		}
+	}
+
+	/**
+	 * TimeLeadLagAggFunction.
+	 */
+	public static class TimeLeadLagAggFunction extends LeadLagAggFunction {
+
+		public TimeLeadLagAggFunction(int operandCount) {
+			super(operandCount);
