+		this.aggsHandleFunction = null;
+	}
+
+	@Override
+	public void prepare(ResettableExternalBuffer rows) throws Exception {
+		if (inputIterator != null) {
+			inputIterator.close();
+		}
+		inputIterator = rows.newIterator();
+		if (inputIterator.advanceNext()) {
